module.exports = [
  {
    id: 'development-milestones-context', chapterId: 'sp5355-ch-01', domainId: 'development-differences', domain: 'Human Development and Individual Learning Differences',
    label: 'Development, Context, and Learner Variability', references: [ETS],
    questions: [
      q('A kindergarten teacher notices that one child reaches several language milestones later than classmates. What is the most appropriate first interpretation?', 'A preschool team sees that one child uses shorter sentences than most same-age peers. Which conclusion is most defensible?', 'Development follows broad patterns, but individual variation requires information from multiple sources and settings before conclusions are drawn.', ['Any difference from a class average proves a disability.', 'The child should immediately receive a fixed disability label.', 'Chronological age no longer matters when planning instruction.'], 'Milestones provide useful reference points, not stand-alone diagnoses. Educators should document functioning across domains, contexts, and time and involve qualified team members before attributing a pattern to disability.', 'foundation'),
      q('A student solves multistep problems during small-group instruction but rarely begins the same work during a noisy whole-class period. What should the teacher examine first?', 'A learner participates successfully in science lab with a visual agenda but disengages during unstructured project time. What is the best next step?', 'Compare task demands, environmental conditions, supports, and performance across the two contexts.', ['Assume the student has forgotten the underlying skill.', 'Lower every academic expectation for the student.', 'Treat the difference as deliberate noncompliance.'], 'Performance reflects an interaction among learner skills, task demands, supports, and context. Comparing conditions can identify a removable barrier before the team changes expectations or infers a stable trait.'),
      q('A teacher wants to understand a learner’s self-regulation needs. Which information is most useful?', 'A team is planning supports for a student who becomes overwhelmed during independent work. Which data set offers the strongest starting point?', 'Observations of triggers, strategies used, recovery, and successful conditions across routines.', ['A single global rating completed months ago.', 'The disability category without current observations.', 'The average behavior of the rest of the class.'], 'Self-regulation is best understood through specific, current observations of what precedes difficulty, how the learner responds, which strategies help, and whether patterns differ by setting or task.'),
      q('A multilingual learner has difficulty following rapid oral directions in English but demonstrates the task after a peer models it. Which interpretation is best?', 'A student learning English gives brief oral responses but accurately sorts and explains concepts with drawings in the home language. What should the team conclude first?', 'Language access may be affecting the demonstration of knowledge, so the team should gather culturally and linguistically appropriate evidence.', ['The performance automatically establishes an intellectual disability.', 'Visual modeling should be removed to reveal the true score.', 'Home-language information is irrelevant to educational planning.'], 'Difference is not disability. The team should distinguish language acquisition and access from disability by using multiple methods, appropriate language supports, and information about performance in the learner’s languages.'),
      q('A middle school student with a disability is embarrassed when an adult uses babyish materials for a functional routine. What principle should guide revision?', 'A high school learner practices daily-living skills with worksheets designed for very young children. What is the best instructional change?', 'Use age-respectful materials while matching the instructional steps and supports to the learner’s current needs.', ['Match all materials to developmental level regardless of age.', 'Stop teaching functional skills until grade-level mastery is reached.', 'Ask peers to complete the routine for the student.'], 'Instruction can be individualized without sacrificing dignity. Materials and contexts should be chronological-age respectful, while prompts, task steps, and response modes are adapted to the learner’s present performance.'),
      q('A student performs a social routine only with one familiar adult. Which plan best promotes generalization?', 'A learner uses a requesting strategy in the resource room but not in the cafeteria. What should the team do?', 'Practice the same skill with planned variations in people, materials, and natural settings, then fade prompts.', ['Repeat the skill only in the original setting until it is perfect.', 'Introduce several unrelated target skills at the same time.', 'Wait for generalization to occur without programming it.'], 'Generalization is more likely when instruction deliberately varies relevant people, materials, and settings, reinforces the skill in natural routines, and gradually transfers stimulus control away from adult prompts.'),
      q('A team is writing a learner profile. Which statement is most useful for planning?', 'Which present-level statement gives an IEP team the most actionable developmental information?', 'The student follows a two-step visual routine independently and needs one verbal prompt when the sequence changes.', ['The student is low functioning in most situations.', 'The student has autism and therefore prefers routines.', 'The student is developmentally much younger than peers.'], 'Objective descriptions identify a demonstrated strength, a specific condition, and the support needed. Global labels and assumptions based on category do not tell the team what to teach or how to measure change.'),
      q('A learner’s participation drops after a recent family move and change in transportation. How should the school respond?', 'A student’s work completion changes sharply after housing instability disrupts sleep and attendance. What is the best interpretation?', 'Consider environmental changes alongside disability-related needs and coordinate supports without blaming the learner or family.', ['Attribute the change entirely to the disability category.', 'Remove the student from general education immediately.', 'Ignore nonacademic factors because they are outside instruction.'], 'Development and learning are influenced by environmental as well as biological factors. A responsive team gathers context, protects privacy, stabilizes access, and avoids treating a situational change as proof of a new disability need.'),
      q('A teacher records one difficult morning and says a student has lost a previously learned skill. What evidence is needed before changing the program?', 'After one poor assessment session, a team proposes a major reduction in expectations. What should happen first?', 'Collect repeated observations and work samples under representative conditions and compare them with prior data.', ['Make the change because the most recent event is always most valid.', 'Use the disability label as the only source of evidence.', 'Wait until the annual review and gather no additional data.'], 'A single observation may be affected by health, context, fatigue, or task features. Repeated measures and comparison with baseline information support a more reliable decision about whether performance truly changed.'),
    ],
  },
  {
    id: 'disability-characteristics-impact', chapterId: 'sp5355-ch-02', domainId: 'development-differences', domain: 'Human Development and Individual Learning Differences',
    label: 'Disability Characteristics and Educational Impact', references: [ETS],
    questions: [
      q('A student with a specific learning disability reads grade-level text accurately but cannot organize written paragraphs. Which response is best?', 'A learner identified with SLD calculates accurately but has persistent difficulty decoding unfamiliar words. What should guide support?', 'Target the documented area of academic need instead of assuming the disability affects every subject in the same way.', ['Provide identical remediation in all academic areas.', 'Infer low overall intelligence from the one difficulty.', 'Replace instruction with permanent adult completion.'], 'Specific learning disabilities can affect particular psychological processes and academic skills unevenly. Instruction should be based on the learner’s actual pattern of strengths and needs, not a global assumption.'),
      q('A student with autism covers their ears during fire-drill announcements and then misses directions. Which support is most responsive?', 'A learner with ASD becomes distressed when a loud timer signals transitions. What is the best initial support?', 'Plan a predictable, accessible warning and communication routine while teaching the student how to use it.', ['Interpret the response as intentional defiance.', 'Exclude the student from every future drill.', 'Require exposure without preparation until the response stops.'], 'Sensory and communication needs can affect access and behavior. A predictable warning, accessible direction, and taught coping or communication response support participation while preserving safety requirements.'),
      q('A student with ADHD begins work when directions are chunked and a checklist is visible. What does this pattern suggest?', 'A learner with ADHD completes projects with interim deadlines but misses work when given one distant due date. Which interpretation is best?', 'Executive-function supports are improving task initiation, organization, and monitoring.', ['The student knew the work and was choosing to fail before.', 'The checklist has changed the academic standard.', 'The disability affects intelligence rather than self-management.'], 'ADHD may affect executive functions such as initiation, working memory, inhibition, and organization. External structures can support performance without changing the learning target or implying weak ability.'),
      q('A student with an emotional or behavioral disability argues mainly during unpredictable peer-group tasks. What perspective is most useful?', 'A learner with EBD withdraws during competitive activities but participates during structured cooperative routines. What should the team examine?', 'Examine interactions among the learner, task, peers, expectations, and consequences rather than locating the problem only within the child.', ['Assume the behavior will occur equally in every setting.', 'Conclude that peers alone caused the disability.', 'Remove all social learning opportunities permanently.'], 'An ecological perspective considers how behavior emerges through interactions between the learner and the environment. Context-specific data can guide prevention, instruction, and reinforcement of more effective responses.'),
      q('Which information is essential when considering educational needs associated with intellectual disability?', 'A team is reviewing support needs for a student with an intellectual disability. Which evidence is most central?', 'Information about both intellectual functioning and adaptive behavior across conceptual, social, and practical domains.', ['A reading score by itself.', 'Physical appearance and medical history only.', 'The expectations of one classroom without other contexts.'], 'Intellectual disability involves limitations in intellectual functioning and adaptive behavior. Educational planning therefore considers functional conceptual, social, and practical performance across relevant environments.'),
      q('A student understands grade-level ideas but has difficulty producing clear speech. What is the most appropriate instructional assumption?', 'A learner uses an AAC system and needs extra response time during discussion. Which teacher response is best?', 'Presume competence, provide an effective communication mode, and assess knowledge without making speech production the unintended barrier.', ['Reduce cognitive demand because speech is unclear.', 'Answer every question for the student.', 'Require oral speech before accepting any academic response.'], 'A communication disability can limit how knowledge is expressed without indicating limited understanding. Accessible response modes and adequate wait time help the student demonstrate the intended construct.'),
      q('A learner has both a visual impairment and a motor disability. How should the team plan access?', 'A student has hearing, mobility, and health-related needs that interact during laboratory work. What is the best approach?', 'Analyze the combined effect of the needs on each task and coordinate individualized supports across specialists.', ['Add separate generic supports for each label without testing them together.', 'Choose the support associated with the first diagnosis only.', 'Assume the effects can be predicted from category names.'], 'Co-occurring disabilities may interact in ways that are not captured by treating each label separately. Collaborative task analysis and trials show how combined access, communication, positioning, and health supports function.'),
      q('A student with dyslexia reads familiar words from memory but struggles to decode new words. Which instruction most directly addresses the need?', 'A learner with persistent word-reading difficulty guesses unfamiliar words from pictures and first letters. What is the strongest instructional focus?', 'Explicit, systematic instruction in sound-symbol relationships and word analysis with cumulative practice.', ['Silent independent reading without corrective feedback.', 'Memorizing the appearance of every possible word.', 'Replacing reading with listening for all future tasks.'], 'Dyslexia commonly involves accurate or fluent word recognition, decoding, and spelling. Explicit, systematic instruction with modeling, guided practice, cumulative review, and feedback directly addresses these skills.'),
      q('Two students share the same disability category but respond differently to the same scaffold. What should the teacher do?', 'Students with the same eligibility label show different strengths, communication preferences, and support needs. What follows?', 'Use individual performance data to select, monitor, and revise supports for each learner.', ['Standardize support solely by disability category.', 'Keep the scaffold unchanged to ensure fairness.', 'Infer that one student was incorrectly identified.'], 'A disability category does not prescribe a single instructional profile. Individualized planning uses current performance, preferences, goals, and response data to decide which supports help each learner.'),
    ],
  },
  {
    id: 'adaptive-sensory-health-supports', chapterId: 'sp5355-ch-03', domainId: 'development-differences', domain: 'Human Development and Individual Learning Differences',
    label: 'Adaptive, Sensory, Physical, and Health Supports', references: [ETS, IDEA_IEP_REVIEW],
    questions: [
      q('A student with low vision receives a worksheet containing a dense unlabeled diagram. What is the best access response?', 'A learner who is blind is assigned a graph that is available only as a small image. What should the team provide?', 'An equivalent accessible representation, such as a clear verbal description, tactile graphic, or usable enlarged version matched to the learner.', ['A different activity with no connection to the same concept.', 'A peer’s completed answers to copy.', 'More time to view the unchanged inaccessible image.'], 'Access means preserving the intended concept while changing how information is perceived when necessary. The appropriate representation depends on the learner’s assessed media and access needs.'),
      q('A student who is deaf uses sign language and will join a fast-paced seminar. Which plan best supports communication access?', 'A hard-of-hearing student is entering a discussion-heavy class. What should the IEP team consider?', 'The student’s communication mode, direct communication opportunities, acoustics, assistive technology, and access to all speakers.', ['Seat location as the only consideration.', 'Written homework instead of participation in discussion.', 'A rule that classmates may speak without being identified.'], 'Communication access is broader than hearing volume. Planning should address the learner’s language and mode, visibility or audibility of speakers, technology, peer access, and direct instruction needs.'),
      q('A student with a physical disability needs support positioning materials during science lab. What is the teacher’s best action?', 'A learner with limited motor control cannot safely reach equipment in a standard workstation. Which response is best?', 'Coordinate with the student and relevant specialists to arrange accessible positioning and equipment while preserving active participation.', ['Assign an observer role for every laboratory activity.', 'Move the student without consulting the established plan.', 'Have a peer perform all experimental decisions and actions.'], 'Physical access should enable meaningful participation and follow established safety, positioning, and equipment guidance. Collaboration prevents unsafe improvisation and avoids unnecessary removal of learner agency.'),
      q('A student has a documented seizure action plan. During a classroom seizure, what should staff do first?', 'A learner with a health condition experiences the event described in the school emergency plan. What is the correct response?', 'Follow the individualized emergency plan, protect safety, and activate trained medical or emergency procedures as specified.', ['Create a new response based on what seems convenient.', 'Give food or medication not authorized in the plan.', 'Delay action until a family member can be reached.'], 'Health supports in school must follow the individualized plan, staff training, delegation rules, and emergency procedures. Improvised treatment can create risk and exceed an educator’s role.'),
      q('Which goal best addresses adaptive behavior?', 'A team wants to measure growth in practical daily functioning. Which target is most appropriate?', 'Given a visual checklist, the student will complete four steps for purchasing a cafeteria item in four of five opportunities.', ['The student will improve independence soon.', 'The student will earn higher intelligence-test scores.', 'The student will behave like same-age peers at all times.'], 'Adaptive goals should identify a meaningful conceptual, social, or practical routine and specify observable conditions, performance, and criteria. Vague comparisons do not support instruction or progress monitoring.'),
      q('A team is considering text-to-speech for a student who understands content but reads print slowly. What is the best next step?', 'A learner may benefit from speech-to-text for extended writing. How should the team decide?', 'Conduct a task-focused trial, teach use of the tool, and compare access and performance data with and without it.', ['Purchase the most expensive device without a trial.', 'Reject the tool because it may also help classmates.', 'Use the disability label as proof that the tool will work.'], 'Assistive technology decisions are individualized. A structured trial examines whether the tool reduces the relevant barrier, is usable in authentic settings, and improves access without undermining the target skill.'),
      q('A school places every student with a particular disability in the same separate classroom. What is the central problem?', 'A district assigns placement from disability category before reviewing individual needs. Which principle is violated?', 'Placement must be individually determined from the IEP and LRE requirements, not automatically assigned by category.', ['Separate placement is always prohibited.', 'Parents alone must select the classroom without a team process.', 'Placement can never change after the initial decision.'], 'IDEA requires an individualized placement decision based on the IEP and least restrictive environment requirements. A continuum must be available, but no point on it is automatic for a category.'),
      q('Fluorescent glare and hallway noise interfere with a learner’s sustained work. Which response is most appropriate?', 'A student’s participation improves in a low-distraction area with predictable sensory breaks. What should the team do?', 'Document the conditions, provide an individualized environmental support, and monitor whether access and participation improve.', ['Remove all academic demands whenever the student is uncomfortable.', 'Assume the same sensory plan is appropriate for every learner.', 'Use the support only as a reward for compliant behavior.'], 'Environmental adaptations should respond to documented sensory access needs and be evaluated by their effect on meaningful participation. They are access supports, not rewards or universal prescriptions.'),
    ],
  },
  {
    id: 'individualized-planning-transition', chapterId: 'sp5355-ch-04', domainId: 'planning-instruction-environment', domain: 'Effective Planning and Instruction and Productive Learning Environments',
    label: 'Individualized Planning, IEPs, LRE, and Transition', references: [ETS, IDEA_IEP, IDEA_IEP_REVIEW, IDEA_LRE, IDEA_PLACEMENT],
    questions: [
      q('Which present-level statement best supports individualized planning?', 'An IEP team needs a useful present-level statement for written expression. Which example is strongest?', 'On three curriculum writing samples, the student wrote a clear topic sentence in two of three paragraphs and included supporting details in one.', ['The student is significantly below grade level.', 'The student dislikes writing and needs help.', 'The student has SLD in written expression.'], 'Present levels should describe current, measurable academic or functional performance and how disability affects progress. Specific baseline evidence supports goal design and later comparison.'),
      q('Which IEP goal is measurable?', 'A team is revising a vague reading goal. Which replacement is most measurable?', 'Given a 150-word instructional-level passage, the student will read at least 120 correct words per minute on three consecutive weekly probes.', ['The student will improve reading fluency.', 'The student will try harder when reading aloud.', 'The student will become a confident reader by spring.'], 'A measurable annual goal states the condition, observable behavior, criterion, and often a consistency requirement. These features permit repeated progress measurement and instructional decisions.'),
      q('An IEP contains a measurable goal but no description of how progress will be measured. What is missing?', 'A family asks how the team will know whether an annual math goal is being achieved. What must the IEP specify?', 'The measurement method and schedule for periodic progress reports.', ['A guarantee that the student will meet the goal.', 'A comparison with every classmate each week.', 'A new disability category for each skill deficit.'], 'IDEA requires the IEP to describe how progress toward annual goals will be measured and when periodic reports will be provided. A goal without a monitoring plan is incomplete for decision making.'),
      q('A student’s goal targets independent paragraph planning, but the service description addresses only oral reading. What should the team do?', 'An IEP goal addresses functional communication, while listed services contain no communication instruction or support. What is the best response?', 'Align specially designed instruction, services, supports, and progress monitoring with the identified need and goal.', ['Keep the mismatch because services and goals are unrelated sections.', 'Delete the goal rather than examine the program.', 'Use a generic service package assigned by category.'], 'IEP components should form a coherent program: present needs lead to measurable goals, services and supports address those goals, and progress measures show whether the program is effective.'),
      q('A student is allowed to use a calculator on a test that measures multistep problem solving, not computation. This is best described as what?', 'A learner receives extended time on a reading-comprehension assessment when speed is not the target. What kind of change is this?', 'An accommodation that changes access or response conditions without changing the intended construct.', ['A modification that lowers the learning target.', 'An alternate assessment automatically required by disability.', 'A placement decision.'], 'An accommodation changes how a learner accesses or responds while preserving what is measured. A modification changes the expected content, complexity, or performance standard.'),
      q('During IEP development, when should assistive technology be considered?', 'A student has difficulty accessing grade-level text and producing written responses. What is the team’s AT responsibility?', 'The team should consider whether assistive technology devices or services are needed for the individual learner.', ['Only after every low-technology support has failed for a full year.', 'Only when a parent has already purchased a device.', 'Only for students with physical disabilities.'], 'IDEA requires the IEP team to consider whether the child needs assistive technology. Consideration is individualized and task-based; it is not restricted to a disability type or private purchase.'),
      q('Which information must the IEP team consider during development?', 'A team is drafting an IEP primarily from test deficits. Which additional information must be considered?', 'The learner’s strengths, parent concerns, evaluation results, and academic, developmental, and functional needs.', ['Only the lowest standardized score.', 'Only services already available at the school.', 'Only the special educator’s preferred program.'], 'Federal IEP requirements direct the team to consider strengths, parent concerns, evaluation results, and the child’s academic, developmental, and functional needs rather than start from a preset service menu.'),
      q('A student can make progress in general education with supplementary aids, but the team prefers a separate class because scheduling is easier. What should govern placement?', 'A school proposes a more restrictive setting because staff assignments are convenient. What is the correct placement principle?', 'The individualized IEP and LRE analysis, including whether education with nondisabled peers can succeed with supplementary aids and services.', ['Administrative convenience.', 'The disability category by itself.', 'The location with the most specialized equipment regardless of need.'], 'Placement is individually determined, based on the IEP, and as close as possible to the child’s home. Removal from regular education occurs only when education there cannot be achieved satisfactorily with supports.'),
      q('Under the federal IDEA baseline, by when must transition content begin in the IEP unless the team determines an earlier age is appropriate?', 'A team asks when federal IDEA requires measurable postsecondary goals and transition services to appear. What is the correct baseline?', 'No later than the first IEP in effect when the student turns 16, updated annually, or earlier when appropriate.', ['Only during the student’s final semester of high school.', 'At age 18 in every state.', 'Only after the student has accepted a job.'], 'The federal IDEA baseline begins no later than the first IEP in effect at age 16, with annual updates, and permits earlier planning. States may impose an earlier requirement, so current local rules also matter.'),
      q('Which transition goal is based on an age-appropriate transition assessment?', 'A student’s interest inventory and job-shadow evaluation show a sustained interest and skill in culinary work. Which postsecondary goal is strongest?', 'After high school, the student will enroll in a culinary certificate program and seek supported employment in food service.', ['The student will explore careers sometime.', 'The student will pass every current class.', 'The student will behave appropriately at school.'], 'Measurable postsecondary goals describe intended outcomes after high school in education or training, employment, and when appropriate independent living, and they are grounded in age-appropriate transition assessment.'),
      q('What distinguishes an IFSP emphasis from a school-age IEP emphasis at a high level?', 'A candidate compares early-intervention IFSP planning with school-age IEP planning. Which statement is most accurate?', 'An IFSP is family-centered and addresses early-intervention outcomes in natural environments, while an IEP addresses the child’s school-age educational program.', ['An IFSP is simply an IEP with a different title.', 'An IFSP excludes family priorities from planning.', 'An IEP is a medical treatment plan written by a physician.'], 'IFSP and IEP requirements differ by age, system, and focus. For this exam, the key distinction is family-centered early intervention and natural environments versus the school-age educational program.'),
    ],
  },
  {
    id: 'explicit-instruction-curriculum-access', chapterId: 'sp5355-ch-05', domainId: 'planning-instruction-environment', domain: 'Effective Planning and Instruction and Productive Learning Environments',
    label: 'Explicit Instruction and Curriculum Access', references: [ETS, IES_READING, IES_MATH],
    questions: [
      q('A teacher introduces a new strategy by naming it, modeling a think-aloud, guiding several examples, checking responses, and then assigning independent practice. What approach is this?', 'Which lesson sequence best illustrates explicit and systematic instruction?', 'A clear model-guided practice-independent practice sequence with frequent checks and corrective feedback.', ['Discovery learning with no initial explanation.', 'Permanent prompting that prevents independent responding.', 'Unstructured repetition of the same worksheet.'], 'Explicit instruction makes the target and thinking visible, sequences examples, elicits frequent responses, provides feedback, and transfers responsibility as learners demonstrate readiness.'),
      q('A learner is acquiring a multistep hand-washing routine. What is the purpose of task analysis?', 'A student is learning to use a school copier independently. Why would the teacher begin with a task analysis?', 'To break the complex routine into observable, teachable steps that can be prompted, measured, and chained.', ['To measure general intelligence.', 'To remove all natural variation from the routine.', 'To replace instruction with a written test.'], 'Task analysis identifies the component steps and their sequence. The teacher can then select a chaining approach, teach missing steps, record performance, and fade prompts toward independence.'),
      q('A student solves equations accurately with a step card. What should happen next?', 'A learner independently uses a paragraph organizer on four consecutive assignments. How should the scaffold change?', 'Gradually fade or simplify the scaffold while monitoring whether independent accuracy is maintained.', ['Remove all support abruptly and stop collecting data.', 'Keep every prompt permanently regardless of performance.', 'Increase the task difficulty and the prompts at the same time without checking.'], 'Scaffolds are temporary supports. Planned fading based on performance data promotes independence while monitoring guards against removing the support faster than the learner can maintain success.'),
      q('Which lesson design best reflects Universal Design for Learning?', 'A teacher is planning a unit for learners with varied language, sensory, and executive-function needs. Which design is most consistent with UDL?', 'Define a clear goal, anticipate barriers, and offer purposeful options for engagement, representation, and action or expression.', ['Create a separate lower goal for every student before instruction.', 'Offer many decorative choices unrelated to the goal.', 'Wait until learners fail before considering access.'], 'UDL is proactive design around a common, clear goal. Options are selected because they reduce predictable barriers while preserving the intended learning target, not merely because they add variety.'),
      q('A student guesses unfamiliar words from pictures. Which instructional response best targets decoding?', 'A learner reads known words but cannot sound out unfamiliar regular words. What should instruction emphasize?', 'Explicit, cumulative practice connecting phonemes with graphemes and blending them to read words.', ['More silent reading with no word-level instruction.', 'Memorizing story illustrations.', 'Asking the student to infer every word from context.'], 'Decoding instruction makes sound-symbol relationships and blending procedures explicit, provides cumulative guided practice, and gives immediate corrective feedback rather than relying on guessing.'),
      q('A student reads accurately but slowly and without phrasing. Which practice is best matched to the need?', 'A learner’s word reading is accurate, but oral reading is labored. What is the strongest fluency support?', 'Modeled and repeated oral reading of appropriate text with feedback on accuracy, rate, and phrasing.', ['Independent exposure to much harder text.', 'Copying definitions before each reading.', 'Replacing all reading with audio permanently.'], 'Fluency practice should use text at an appropriate level, a model of fluent reading, repeated opportunities, and feedback. It builds automaticity and prosody without confusing speed with comprehension.'),
      q('A learner can decode a passage but cannot explain its meaning. Which instruction is most appropriate?', 'A student reads content-area text accurately yet misses causal relationships. What should the teacher do?', 'Teach a comprehension strategy explicitly, model its use, guide practice with the text, and ask the student to justify understanding with evidence.', ['Return exclusively to letter-sound drills.', 'Supply the answers before the student reads.', 'Grade the passage repeatedly without teaching a strategy.'], 'Accurate decoding does not guarantee comprehension. Explicit modeling and guided use of a relevant strategy—such as identifying cause and effect, summarizing, or monitoring meaning—targets the observed need.'),
      q('A student is learning subtraction with regrouping but treats each digit independently. Which representation sequence is most helpful?', 'A learner does not understand why ten ones can be exchanged for one ten. Which instructional sequence is strongest?', 'Use concrete base-ten materials, connect them to drawings, and then link both to the written algorithm.', ['Require memorization of the algorithm without meaning.', 'Begin with timed tests and no models.', 'Switch to an unrelated operation.'], 'Concrete and visual representations can make place-value exchanges visible. Explicitly connecting each representation to mathematical symbols supports conceptual understanding and accurate procedural use.'),
      q('A teacher sees that a student repeatedly subtracts the smaller digit from the larger digit regardless of position. What feedback is best?', 'A learner consistently reverses numerator and denominator when forming ratios. What should the teacher do first?', 'Identify the error pattern, model the governing relationship, and provide a closely matched example for guided correction.', ['Mark only the total score and assign more of the same work.', 'Praise effort without addressing the misconception.', 'Give the correct answer with no explanation or student response.'], 'Error analysis reveals the misconception driving repeated errors. Specific feedback and a guided comparison help the learner revise the rule, after which new examples can test whether the correction transfers.'),
      q('When is flexible grouping most appropriate?', 'A teacher wants groups that respond to changing skill needs rather than fixed labels. What should guide grouping?', 'Use current learning data and the purpose of the lesson, then regroup as needs and performance change.', ['Use disability categories as permanent reading groups.', 'Group students by perceived motivation only.', 'Keep the same groups all year to avoid new data.'], 'Flexible grouping is purposeful and temporary. Recent performance, task goals, and needed intensity guide membership, and ongoing evidence indicates when students should move or the group focus should change.'),
      q('A student rushes through multistep work without checking. Which metacognitive support is best?', 'A learner completes a strategy correctly during modeling but does not monitor independent work. What should the teacher add?', 'Model a brief plan-do-check think-aloud and provide a self-questioning cue that is faded with successful use.', ['Increase the amount of work without a strategy.', 'Have an adult correct every step before the student sees it.', 'Tell the student simply to be more careful.'], 'Metacognitive instruction makes planning, monitoring, and evaluation visible. A concise self-questioning routine gives the learner an actionable process and can be faded as self-regulation develops.'),
    ],
  },
  {
    id: 'behavior-environments-engagement', chapterId: 'sp5355-ch-06', domainId: 'planning-instruction-environment', domain: 'Effective Planning and Instruction and Productive Learning Environments',
    label: 'Behavior, Engagement, and Productive Environments', references: [ETS, IES_BEHAVIOR, IDEA_IEP_REVIEW],
    questions: [
      q('A class loses instructional time because arrival routines change each day. Which preventive support is best?', 'Students frequently ask what to do during the first ten minutes of class. What should the teacher establish?', 'Teach, model, practice, and visually display a short consistent arrival routine, then acknowledge successful use.', ['Wait for errors and deliver increasingly severe consequences.', 'Post a long rule list without instruction or practice.', 'Change the routine often to build flexibility immediately.'], 'Predictable routines reduce ambiguity and increase available learning time. Expectations become useful when they are explicitly taught, practiced in context, prompted as needed, and reinforced consistently.'),
      q('A student tears worksheets after receiving a long independent assignment, and the task is then removed. Which information is most relevant to a functional hypothesis?', 'A learner shouts during difficult writing tasks and is sent to the hallway each time. What pattern should the team examine?', 'The antecedent task, the observable behavior, and the consequence of escaping or delaying the work.', ['The student’s personality type.', 'Whether the behavior annoys adults.', 'A list of consequences used with other students.'], 'Functional assessment examines relationships among antecedents, observable behavior, and consequences. Repeated removal of a difficult task may maintain behavior through escape, a hypothesis that must be tested with data.'),
      q('An FBA suggests that disruption reliably produces peer attention. Which BIP component is most important?', 'Data indicate that calling out is maintained by adult interaction. Which intervention is best aligned with function?', 'Teach and reinforce an efficient appropriate way to request attention while adjusting antecedents and consequences that maintain disruption.', ['Use a punishment unrelated to attention.', 'Remove academic instruction permanently.', 'Teach a break request even though escape is not the identified function.'], 'A function-based plan should prevent predictable triggers, teach a socially appropriate replacement that serves the same function, and arrange consequences so the replacement is more efficient and successful.'),
      q('Which replacement behavior is best for a student who leaves work to escape confusing directions?', 'A learner crumples assignments when the first step is unclear. Which replacement skill is most functionally equivalent?', 'Use a taught help card to request clarification or a brief guided start.', ['Remain silent until the period ends.', 'Ask for peer attention unrelated to the task.', 'Complete a preferred activity without permission.'], 'A replacement behavior must be teachable, efficient, and serve the same function as the problem behavior. Requesting clarification addresses escape from confusion while keeping the learner engaged in the task.'),
      q('A teacher says, “You opened your notebook and began within one minute—that followed our start routine.” Why is this feedback effective?', 'Which acknowledgment best strengthens an expected transition behavior?', 'It is immediate and behavior-specific, linking the student’s action to the taught expectation.', ['It praises a fixed trait rather than an action.', 'It delays feedback until the end of the month.', 'It depends on comparing the student with classmates.'], 'Behavior-specific praise names the observable action and its connection to an expectation. Immediate, contingent feedback helps learners identify what to repeat and is more informative than global approval.'),
      q('A teacher wants to increase engagement during review. Which change is most likely to help?', 'During a long lecture, only one student responds every several minutes. What is the best instructional adjustment?', 'Build frequent, varied opportunities for all students to respond and give brief feedback.', ['Extend the lecture and reduce questions.', 'Call only on the quickest volunteer.', 'Assign the review as punishment after class.'], 'Frequent opportunities to respond—such as response cards, partner rehearsal, brief writing, or choral responses—produce active practice and give the teacher information for immediate adjustment.'),
      q('A student avoids beginning writing when only one topic is assigned. Which low-intensity support may increase agency without changing the target?', 'A learner engages more consistently when allowed to choose the order of two required tasks. What principle is illustrated?', 'Offer a bounded choice among options that all meet the same instructional goal.', ['Let the student omit the learning goal entirely.', 'Provide unlimited choices with no clear expectations.', 'Select a different academic standard for convenience.'], 'Instructional choice can increase engagement and agency when each option remains aligned to the same goal. Bounded choices are clear enough to avoid adding executive-function demands.'),
      q('A student is escalating verbally after an unexpected schedule change. What should staff prioritize?', 'During a conflict, a learner shows signs of increasing distress and cannot process lengthy language. What is the best immediate response?', 'Follow the safety and support plan, reduce verbal demands, use calm predictable communication, and allow regulated space as specified.', ['Debate the student until the student admits fault.', 'Add several new directions rapidly.', 'Use an unapproved restraint for convenience.'], 'During escalation, staff should follow established safety procedures, reduce unnecessary stimulation and language, and avoid power struggles. Any emergency intervention must comply with law, policy, training, and the individual plan.'),
      q('A learner becomes distressed when activities end without warning. Which support is most preventive?', 'A student misses instructions whenever the class shifts unexpectedly between locations. What should the teacher add?', 'Use a predictable transition cue, visual schedule, brief preview of changes, and explicit practice of the transition routine.', ['Deliver consequences after every missed cue without teaching.', 'Eliminate all transitions from the school day.', 'Ask classmates to physically move the student.'], 'Advance cues and visual schedules make time and sequence more predictable. Explicit practice and reinforcement teach what to do, while planned previews help the learner respond to unavoidable changes.'),
      q('A behavior plan appears ineffective after two weeks. What should the team check before concluding the hypothesis was wrong?', 'Student outcome data are flat after a new intervention begins. Which additional evidence is essential?', 'Implementation-fidelity data showing whether the planned supports, instruction, and consequences were delivered as designed.', ['Whether staff personally like the intervention.', 'The number of pages in the written plan.', 'Whether the learner received a new label.'], 'Outcome data cannot be interpreted well without fidelity information. If the plan was not implemented consistently, the team cannot tell whether the intervention itself was ineffective or was never adequately tested.'),
    ],
  },
  {
    id: 'assessment-quality-selection', chapterId: 'sp5355-ch-07', domainId: 'assessment', domain: 'Assessment',
    label: 'Assessment Purpose, Quality, and Access', references: [ETS, IDEA_EVAL, IDEA_ASSESS],
    questions: [
      q('A vocabulary test is used to decide whether a student can solve multistep equations. What is the primary concern?', 'A spelling inventory is used as the sole measure of reading comprehension. Which assessment concept is weakest?', 'Validity, because the evidence does not adequately support the intended interpretation and use.', ['Reliability, only because the score is numerical.', 'Efficiency, because the test is short.', 'Norming, because every assessment must be nationally normed.'], 'Validity concerns whether evidence supports the interpretation and use of scores. A measure dominated by a different skill cannot justify a conclusion about the intended construct.'),
      q('A progress measure gives very different scores on consecutive days even though instruction and performance appear stable. What quality is in question?', 'Two trained examiners score the same performance very differently under the same rubric. Which property needs attention?', 'Reliability or consistency of measurement and scoring.', ['Face validity alone.', 'The student’s eligibility category.', 'The length of the IEP.'], 'Reliability concerns consistency across occasions, forms, items, or raters as relevant. Large unexplained variation weakens confidence that score changes reflect actual performance rather than measurement error.'),
      q('Why should an eligibility team use multiple assessment tools and strategies?', 'A team has one low standardized score and must decide whether a student has a disability and needs special education. What is required?', 'Different sources can test converging explanations and prevent one measure from becoming the sole criterion.', ['Multiple measures guarantee the preferred eligibility result.', 'The highest score should automatically replace all others.', 'Informal information is never relevant.'], 'IDEA requires varied tools and strategies and prohibits using a single measure as the sole criterion. Multiple sources help the team understand functional, developmental, academic, and contextual evidence.'),
      q('A newly arrived multilingual learner is assessed only in rapid academic English. What is the central evaluation concern?', 'A student who uses a communication device is evaluated through spoken responses only. What should be changed?', 'Use the native language or appropriate communication mode and a format most likely to show what the learner knows, unless clearly infeasible.', ['Translate the final score but keep the inaccessible administration.', 'Assume low performance proves disability.', 'Exclude parent and language-history information.'], 'Evaluation procedures must reduce racial, cultural, linguistic, sensory, manual, and communication barriers so results reflect the intended aptitude or achievement rather than an access limitation.'),
      q('Which assessment is most useful for adjusting tomorrow’s instruction?', 'A teacher wants immediate evidence about which step in a strategy students misunderstand. What should be used?', 'A brief formative task or observation aligned to the taught steps, followed by error analysis.', ['A distant annual accountability score only.', 'An intelligence test unrelated to the lesson.', 'A final course grade after instruction ends.'], 'Formative assessment supplies timely, instructionally relevant evidence during learning. Alignment and error analysis help the teacher decide what to reteach, model differently, or release to independent practice.'),
      q('A reading assessment is intended to measure comprehension, but a student’s documented motor disability prevents use of the response booklet. What is the best response?', 'A student understands science content but cannot manipulate the standard answer sheet. How should the assessment be administered?', 'Provide an appropriate response accommodation that removes the motor barrier without changing the content construct.', ['Lower the content standard automatically.', 'Score unanswered items as lack of science knowledge.', 'Give hints that reveal the correct content answers.'], 'An appropriate accommodation improves access while preserving the construct. The team should avoid both construct-irrelevant motor barriers and supports that supply the knowledge being measured.'),
      q('What does a criterion-referenced interpretation show?', 'A teacher reports that a student correctly performs seven of eight defined skill steps. What kind of interpretation is this?', 'Performance relative to specified skills or standards rather than relative standing among peers.', ['The student’s percentile rank in a norm group.', 'The stability of the score across raters.', 'The cause of the student’s disability.'], 'Criterion-referenced results describe mastery of defined content or performance criteria. Norm-referenced results describe relative position within a comparison group; neither alone establishes disability cause.'),
      q('Which observation definition is most useful for collecting behavior data?', 'A team wants different observers to record the same target consistently. Which definition is strongest?', '“Leaves seat” means both feet cross the desk-area boundary without teacher permission during independent work.', ['The student is disruptive.', 'The student behaves badly too often.', 'The student shows a negative attitude.'], 'An operational definition is observable, measurable, and bounded enough for different people to identify the same event. Labels and inferred attitudes do not produce dependable observation data.'),
    ],
  },
  {
    id: 'evaluation-eligibility-intervention', chapterId: 'sp5355-ch-08', domainId: 'assessment', domain: 'Assessment',
    label: 'Evaluation, Eligibility, and Intervention', references: [ETS, IDEA_EVAL],
    questions: [
      q('A general education team sees persistent difficulty and begins a targeted intervention. What is an appropriate prereferral practice?', 'A student struggles with written expression. Which early intervention step is strongest?', 'Define the concern, implement an evidence-based support with adequate intensity, and monitor response using repeated data.', ['Wait for failure without changing instruction.', 'Promise that intervention data alone will determine eligibility.', 'Use an unrelated worksheet as the only intervention.'], 'Prereferral intervention should be specific, evidence based, implemented as intended, and monitored. It can improve instruction and contribute data, but it does not predetermine eligibility.'),
      q('A school says it will not evaluate a student until every tier of intervention has been completed. What is the problem?', 'A parent requests an evaluation, but the school proposes an indefinite RTI trial first. Which statement is correct?', 'Response-to-intervention procedures may not be used to delay or deny a timely evaluation when disability is suspected.', ['Intervention is prohibited once an evaluation is considered.', 'A parent request automatically makes the student eligible.', 'Only standardized tests may be used in evaluation.'], 'Multi-tiered supports and evaluation can inform one another, but an intervention process cannot become a barrier to IDEA evaluation duties. The agency must follow notice, consent, and timeline requirements.'),
      q('What is the role of parent information in an evaluation?', 'A family describes successful communication strategies that are not visible at school. How should the evaluation team use this information?', 'Treat it as relevant evidence within the required variety of functional, developmental, and academic information.', ['Exclude it because only school data count.', 'Accept it as the sole criterion for eligibility.', 'Use it only after placement has been decided.'], 'IDEA explicitly includes information provided by parents among the sources used in evaluation. It should be integrated with other evidence, not dismissed or made the only basis for a decision.'),
      q('A student is referred for reading difficulty, but records also show significant hearing and communication concerns. How broad should the evaluation be?', 'An evaluation begins with a suspected attention difficulty but reveals motor and language concerns. What must the team do?', 'Assess all areas related to the suspected disability and conduct a sufficiently comprehensive evaluation of educational needs.', ['Test only the original referral concern.', 'Administer one general intelligence measure.', 'Wait until eligibility is decided before examining other needs.'], 'Evaluation must be comprehensive enough to identify special education and related-service needs, including needs not commonly linked to the eventual disability category.'),
      q('Why can no single test score determine special education eligibility?', 'A student earns one unusually low score but shows stronger classroom and curriculum data. What should the team do?', 'Integrate multiple technically sound measures, observations, histories, and contextual information through the team decision process.', ['Ignore every score that conflicts with the lowest one.', 'Average all numbers even when they measure different constructs.', 'Let the test publisher make the eligibility decision.'], 'No single measure may serve as the sole criterion. Teams evaluate patterns, validity, access, instruction, exclusionary factors, functional impact, and need for specially designed instruction.'),
      q('A multilingual learner has had limited access to instruction in English and is referred for SLD. What must the team carefully examine?', 'A student’s reading difficulty appears only in the newly learned school language. Which eligibility safeguard matters most?', 'Whether limited English proficiency or inadequate instruction is the primary explanation, using culturally and linguistically appropriate evidence.', ['Whether the learner speaks English at home exclusively.', 'Whether the disability category would provide more services.', 'Whether one English test falls below average.'], 'Eligibility decisions must not mistake language acquisition, cultural difference, or lack of appropriate instruction for disability. Evidence across languages, instruction, progress, and contexts is necessary.'),
      q('What is the main purpose of a functional behavioral assessment?', 'A student’s serious behavior persists despite general supports. Why would the team conduct an FBA?', 'To identify patterns and develop a testable hypothesis about variables maintaining behavior so intervention can match function.', ['To select the harshest consequence.', 'To diagnose a psychiatric condition from classroom behavior.', 'To prove that the behavior occurs intentionally.'], 'An FBA gathers direct and indirect data about antecedents, behavior, consequences, and context. Its practical purpose is to design and evaluate preventive, instructional, and consequence strategies.'),
      q('After evaluation data are collected, who determines eligibility and educational needs?', 'A multidisciplinary evaluation is complete. What is the next appropriate decision process?', 'A group of qualified professionals and the parent reviews the evidence and applies eligibility criteria through an individualized decision.', ['The classroom teacher decides alone.', 'A computer score automatically assigns the category.', 'The parent is informed only after placement begins.'], 'Eligibility is a team determination using multiple sources and applicable criteria. Parent participation and qualified professional judgment are integral; no test or individual makes the decision automatically.'),
    ],
  },
  {
    id: 'progress-monitoring-data-decisions', chapterId: 'sp5355-ch-09', domainId: 'assessment', domain: 'Assessment',
    label: 'Progress Monitoring and Data-Based Decisions', references: [ETS, IES_DATA, IDEA_IEP],
    questions: [
      q('A student’s weekly reading-fluency scores are 62, 64, 63, 65, and 64 while the goal line rises steadily. What is the best interpretation?', 'A learner’s computation probes remain flat for six weeks while the expected trajectory increases. What should the team conclude?', 'The trend is below the desired rate of improvement, so implementation and instruction should be reviewed rather than waiting for the annual meeting.', ['The most recent one-point increase proves the goal will be met.', 'The student must have reached mastery because scores are stable.', 'Progress data cannot be used between annual reviews.'], 'Progress decisions should compare the pattern or trend with the goal trajectory, not react to one score. A persistently inadequate rate calls for a fidelity check and instructional adjustment.'),
      q('What is the purpose of a goal line on a progress graph?', 'A teacher graphs baseline performance and the expected end-of-year criterion. What does the connecting aim line represent?', 'The expected rate of improvement needed to move from baseline to the goal.', ['The class average on each assessment.', 'A guarantee that the learner will make that progress.', 'The reliability coefficient of the measure.'], 'A goal or aim line visualizes the trajectory from current baseline to the desired outcome. Comparing observed data and trend with that line supports timely, rule-based decisions.'),
      q('How often should progress be measured for a student receiving an intensive intervention?', 'A team needs to know quickly whether a new high-intensity intervention is working. What schedule is best?', 'Frequently enough with a sensitive, repeatable measure to detect meaningful growth and support timely decisions.', ['Only at the annual IEP meeting.', 'On a fixed schedule unrelated to the skill or intervention intensity.', 'Every day using a different unvalidated task.'], 'Monitoring frequency depends on the measure, skill, goal, and decision window. More intensive support typically requires sufficiently frequent comparable data, not arbitrary testing or annual-only review.'),
      q('A family finds a progress graph confusing. What is the clearest explanation?', 'A teacher is presenting progress data to an IEP team. Which communication approach is strongest?', 'Label the skill, baseline, goal, dates, intervention changes, and trend, then explain the educational meaning in plain language.', ['Display raw scores without units or dates.', 'Report only whether the teacher feels encouraged.', 'Use technical terms without inviting questions.'], 'Stakeholders need transparent information about what was measured, under what conditions, what changed, and how the trend compares with the goal. Plain language supports meaningful team participation.'),
      q('A student’s answers show accurate computation but frequent errors choosing the operation in word problems. What should instruction address?', 'Error analysis shows a learner can decode words but misses pronoun referents in connected text. What is the best response?', 'Teach the specific decision or comprehension process revealed by the error pattern and monitor that component.', ['Repeat practice on the already accurate component only.', 'Lower the entire curriculum without targeted teaching.', 'Treat all incorrect answers as the same kind of error.'], 'Total scores can conceal distinct skill patterns. Error analysis identifies which step or concept needs explicit instruction, allowing the teacher to match feedback and practice to the actual barrier.'),
      q('Outcome data improve only in classrooms where the intervention steps are followed. What does this suggest?', 'One teacher implements all components of a plan and sees growth; another omits practice and feedback and sees little change. What should the team examine?', 'Implementation fidelity may be contributing to different outcomes and must be considered before changing the intervention theory.', ['Student labels explain all variation.', 'The plan should be abandoned without checking implementation.', 'Fidelity is irrelevant when outcome scores are available.'], 'Fidelity data show whether the intended intervention was delivered with adequate dosage and quality. They help teams separate an ineffective plan from inconsistent implementation and provide coaching targets.'),
      q('Which decision rule is strongest?', 'A team wants to avoid making program changes from one unusually low score. Which rule is most defensible?', 'If at least four consecutive comparable points fall below the goal line and fidelity is adequate, review and adjust instruction.', ['Change programs after any single low point.', 'Continue unchanged until the end of the year regardless of trend.', 'Change the goal whenever the student misses an item.'], 'A prespecified rule based on multiple comparable observations, trend, and fidelity reduces overreaction to measurement noise while still prompting timely response to an inadequate trajectory.'),
    ],
  },
  {
    id: 'law-ethics-equity', chapterId: 'sp5355-ch-10', domainId: 'professional-practice-collaboration', domain: 'Professional Learning, Practice, and Collaboration',
    label: 'Law, Ethics, Safeguards, and Equity', references: [ETS, IDEA_SAFEGUARDS, IDEA_EVAL, SECTION_504, IDEA_DISCIPLINE],
    questions: [
      q('What does FAPE require at a foundational level under IDEA?', 'A candidate is asked to distinguish FAPE from a guarantee of a particular outcome. Which statement is best?', 'Eligible students receive special education and related services at public expense through an appropriately developed and implemented IEP.', ['Schools guarantee that every student reaches the same achievement level.', 'Families must pay for required related services.', 'A disability label alone determines a standard program.'], 'FAPE concerns an individualized public educational program and required services provided without charge under IDEA procedures. It does not promise a specific score or justify a category-based program.'),
      q('A school suspects a disability in a student who is passing classes with extensive informal help. What duty remains relevant?', 'A highly mobile student shows persistent disability-related needs but has not been formally referred. Which IDEA responsibility applies?', 'Child Find requires identification, location, and evaluation of children who may need special education, including those advancing grade to grade.', ['Only families may initiate concern.', 'Passing grades eliminate any evaluation responsibility.', 'The duty begins only after a student fails a course.'], 'Child Find is an affirmative obligation and is not limited to students who are failing or already referred. The school should follow screening, referral, notice, consent, and evaluation procedures as appropriate.'),
      q('A district proposes changing a student’s placement. What procedural communication is required?', 'A school refuses a parent’s requested evaluation. Which safeguard should the parent receive?', 'Prior written notice describing the proposed or refused action, the reasons, evidence considered, and other required information.', ['An informal verbal message after the change occurs.', 'A public announcement naming the student.', 'No explanation when the school believes its choice is correct.'], 'Prior written notice supports informed participation by documenting what the agency proposes or refuses and why, the records or assessments used, alternatives considered, and available safeguards.'),
      q('A teacher wants to discuss a student’s IEP in a public elevator with a colleague who does not serve the student. What should the teacher do?', 'An educator is asked to share identifiable disability information with staff who have no educational need to know. What is the ethical response?', 'Protect confidentiality and discuss educational records only through authorized, private channels with people who have a legitimate role.', ['Share the information because all school employees are entitled to it.', 'Post the IEP summary where substitutes and visitors can read it.', 'Remove the student’s name but include enough details for easy identification.'], 'Confidentiality protects personally identifiable educational information. Professionals should use secure channels, limit access to legitimate educational interests, and follow federal, state, and local record policies.'),
      q('What is a central protection of Section 504 in public schools receiving federal funds?', 'A student has a disability that substantially limits a major life activity but does not need specially designed instruction. Which law may still require equal access supports?', 'Section 504 prohibits disability discrimination and may require accommodations and related aids or services for equal access.', ['Section 504 applies only after IDEA eligibility.', 'Section 504 guarantees admission to any selective program regardless of criteria.', 'Section 504 is limited to physical access in buildings.'], 'Section 504 is a civil-rights law distinct from IDEA eligibility. It protects qualified students from disability discrimination and can require an appropriate plan of access supports.'),
      q('A district’s referral data show one linguistic group is identified at a much higher rate. What is the best professional response?', 'A team notices that behavior referrals disproportionately affect students from one cultural community. What should happen next?', 'Audit definitions, opportunities to learn, referral practices, assessment access, and decision patterns while using culturally responsive multiple-source evidence.', ['Assume the group has a higher true disability rate.', 'Stop evaluating any student from the group.', 'Use the same biased referral score more consistently.'], 'Disproportionality warrants careful examination of systems and individual evidence. Teams should address bias without withholding needed evaluation or assuming that group membership explains an individual learner’s performance.'),
      q('A colleague recommends a restrictive practice based only on social-media testimonials. What is the best ethical response?', 'A popular intervention makes strong claims but offers no credible evidence and conflicts with a student’s plan. What should the teacher do?', 'Use current evidence, professional standards, student data, law and policy, and team review before adopting a practice that affects access or safety.', ['Adopt it immediately because it is popular.', 'Use it secretly so consent and review are unnecessary.', 'Assume personal experience can replace all evidence and safeguards.'], 'Safe and ethical practice integrates credible evidence, individual data, professional competence, legal requirements, and collaborative decision making. Popularity alone does not establish benefit or safety.'),
    ],
  },
  {
    id: 'collaboration-families-teams', chapterId: 'sp5355-ch-11', domainId: 'professional-practice-collaboration', domain: 'Professional Learning, Practice, and Collaboration',
    label: 'Collaboration with Families and School Teams', references: [ETS, IDEA_IEP_REVIEW],
    questions: [
      q('In effective co-teaching, what is the special educator’s role?', 'A co-taught class assigns the special educator only to students with IEPs at the back table. What change is most appropriate?', 'Share planning, instruction, assessment, and responsibility for all learners while bringing specialized expertise to access and specially designed instruction.', ['Act primarily as the general educator’s assistant.', 'Manage behavior while the general educator owns all content.', 'Work only with identified students in every lesson.'], 'Co-teaching is a partnership with shared ownership. Roles may vary by lesson, but both educators contribute to planning, instruction, assessment, classroom management, and access for the whole class.'),
      q('How should a special educator work with a paraprofessional?', 'A paraprofessional is supporting a new communication routine. What is the teacher’s responsibility?', 'Provide clear direction, training, boundaries, observation, and feedback while retaining responsibility for instructional decisions.', ['Delegate IEP development and grading entirely.', 'Expect the paraprofessional to improvise specialized instruction without guidance.', 'Avoid sharing any relevant plan information.'], 'Teachers remain accountable for instruction and supervision. Paraprofessionals need enough authorized information, modeling, and feedback to implement supports consistently without being assigned professional duties outside their role.'),
      q('A family disagrees with the team’s interpretation of progress data. What is the best first response?', 'During a conference, a parent reports that homework performance differs sharply from school data. What should the team do?', 'Listen, clarify the concern, examine the evidence together, invite home-context information, and identify what additional data or action is needed.', ['Dismiss the report because school data are always superior.', 'End the meeting until the family agrees.', 'Change the IEP immediately without reviewing evidence.'], 'Family collaboration is reciprocal. Respectful inquiry can reveal contextual variables and improve the evidence base, while shared review keeps decisions connected to student needs and procedural requirements.'),
      q('A student’s occupational therapist recommends a classroom positioning support. How should the teacher proceed?', 'A speech-language pathologist suggests a communication prompt for use during academic groups. What is the best collaborative action?', 'Clarify the purpose, integrate the support into authentic routines, define roles, and share implementation and outcome data.', ['Use the strategy only during therapy sessions.', 'Modify the recommendation without informing the specialist.', 'Ask the specialist to take full responsibility for classroom learning.'], 'Related services support educational access. Coordination connects specialist expertise with classroom routines, promotes consistency, and creates shared data for determining whether the support is feasible and effective.'),
      q('How can a student contribute meaningfully to an IEP meeting?', 'A transition-age learner will attend the IEP meeting. Which preparation best supports authentic participation?', 'Teach the student to describe strengths, needs, preferences, goals, and helpful supports using an accessible communication format.', ['Give the student a scripted statement with no opportunity for choice.', 'Exclude the student from discussion of future goals.', 'Ask the student to attend without explaining the meeting.'], 'Student participation supports self-determination when learners understand the process and can communicate preferences, evaluate supports, and contribute to goals with whatever access tools they need.'),
      q('Two team members disagree about whether an intervention is working. What is the strongest next step?', 'A general and special educator offer competing explanations for low participation. How should they proceed?', 'Operationalize the concern, review common data and fidelity, test a feasible adjustment, and schedule a time to evaluate the result.', ['Choose the opinion of the staff member with more seniority.', 'Continue arguing without defining the outcome.', 'Change several variables at once and collect no data.'], 'Productive collaboration converts disagreement into a testable question. Shared definitions, data, a planned change, and a follow-up point support learning while keeping the focus on student outcomes.'),
    ],
  },
  {
    id: 'professional-learning-advocacy', chapterId: 'sp5355-ch-12', domainId: 'professional-practice-collaboration', domain: 'Professional Learning, Practice, and Collaboration',
    label: 'Professional Learning, Advocacy, and Boundaries', references: [ETS, IES_DATA, IDEA_IEP_REVIEW],
    questions: [
      q('Which reflection question is most useful after an instructional unit?', 'A teacher wants professional reflection to improve practice rather than document impressions. What should the teacher ask?', 'Which learners met the target, what response patterns occurred, what supports were implemented, and what evidence should change the next lesson?', ['Did I cover every slide in the presentation?', 'Did students appear to like me?', 'Can I attribute all missed goals to student motivation?'], 'Professional reflection links educator actions to observable learner outcomes and implementation evidence. It identifies a specific change to test instead of relying on coverage, popularity, or blame.'),
      q('How should a teacher choose professional development?', 'A special educator has repeated difficulty designing progress measures. Which learning plan is strongest?', 'Select credible training aligned to the identified practice need, apply it with coaching or feedback, and evaluate effects on student evidence.', ['Attend any available session regardless of relevance.', 'Collect certificates without changing practice.', 'Rely only on informal social-media advice.'], 'High-value professional learning is targeted, evidence informed, applied in authentic work, supported by feedback, and evaluated through implementation and learner outcomes rather than attendance alone.'),
      q('A student lacks an accessible communication tool needed to participate. What is an appropriate advocacy step?', 'A required accessibility support is repeatedly unavailable because of a scheduling problem. What should the teacher do?', 'Document the educational impact, use established team and administrative channels, propose feasible solutions, and follow up until access is addressed.', ['Promise resources the teacher cannot authorize.', 'Publicly disclose the student’s records to create pressure.', 'Accept the barrier without informing the team.'], 'Professional advocacy is specific, evidence based, collaborative, and persistent. It protects confidentiality, stays within role, and uses formal channels to address barriers to services, resources, and equitable participation.'),
      q('A student reveals information suggesting immediate risk of harm and asks the teacher to keep it secret. What should the teacher do?', 'An educator learns of a possible abuse or safety concern. Which response is professionally appropriate?', 'Follow mandatory reporting and school safety procedures promptly, share only with authorized personnel, and do not promise confidentiality that cannot be kept.', ['Investigate independently before telling anyone.', 'Promise secrecy to preserve rapport.', 'Discuss the concern with unrelated colleagues.'], 'Safety and reporting duties override a promise of secrecy. Educators should know their jurisdiction and policy, report through required channels, preserve privacy, and avoid conducting an unauthorized investigation.'),
      q('A transition team wants an adult-service agency representative to attend an IEP meeting. What safeguard matters?', 'An outside employment provider may contribute to transition planning. What should the school address before inviting the representative?', 'Obtain the required parent or adult-student consent before inviting an outside agency likely to provide or pay for transition services.', ['Invite any outside provider without notice because transition is discussed.', 'Transfer all school responsibilities to the agency.', 'Wait until after graduation to coordinate services.'], 'Transition collaboration can improve continuity, but outside-agency participation must follow consent and confidentiality requirements. The public agency retains its IDEA responsibilities even when another agency is involved.'),
      q('Why should special educators verify current state and local requirements in addition to studying federal baselines?', 'A candidate learns the federal IDEA transition age but will practice in a state with additional rules. What is the correct professional habit?', 'Federal law establishes a baseline, while state law, licensure rules, and local policy may add timelines, procedures, or protections.', ['Local policy may remove federal rights.', 'One preparation textbook permanently replaces current law.', 'Requirements are identical in every jurisdiction and never change.'], 'Competent practice checks current authoritative requirements. State and local rules can provide additional protections or earlier timelines but cannot reduce controlling federal rights; this study tool is not legal advice.'),
    ],
  },
];

module.exports.sources = { ETS, IDEA_EVAL, IDEA_IEP, IDEA_IEP_REVIEW, IDEA_LRE, IDEA_PLACEMENT, IDEA_ASSESS, IDEA_SAFEGUARDS, IDEA_DISCIPLINE, IES_BEHAVIOR, IES_DATA, IES_READING, IES_MATH, SECTION_504 };
